// Load existing, merge, save
const jsonPath = path.join(__dirname, '../../data/generated-cases.json');
let existing: CaseData[] = [];
try {
  if (fs.existsSync(jsonPath)) existing = JSON.parse(fs.readFileSync(jsonPath, 'utf-8'));
} catch(e) {}

const existingIds = new Set(existing.map(c => c.id));
const newCases = cases.filter(c => !existingIds.has(c.id));
const merged = [...existing, ...newCases];
fs.mkdirSync(path.dirname(jsonPath), { recursive: true });
fs.writeFileSync(jsonPath, JSON.stringify(merged, null, 0));
console.log(`Added ${newCases.length} cases. Total: ${merged.length}`);